import ast, subprocess, sys

REPO = "/home/polaris/wt/phase3a"

files = subprocess.run(
    ["git", "-C", REPO, "diff", "--name-only", "HEAD", "--", "src/"],
    capture_output=True, text=True, check=True
).stdout.split()

def strip_docstrings(tree):
    for node in ast.walk(tree):
        if isinstance(node, (ast.Module, ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
            body = node.body
            if body and isinstance(body[0], ast.Expr) and isinstance(getattr(body[0], "value", None), ast.Constant) and isinstance(body[0].value.value, str):
                node.body = body[1:]
                # keep body non-empty
                if not node.body:
                    node.body = [ast.Pass()]
    return tree

def normalized(src):
    tree = ast.parse(src)
    tree = strip_docstrings(tree)
    return ast.unparse(ast.parse(ast.unparse(tree)))

failures = []
for f in files:
    head_src = subprocess.run(
        ["git", "-C", REPO, "show", f"HEAD:{f}"],
        capture_output=True, text=True
    )
    if head_src.returncode != 0:
        failures.append(f"{f}: not in HEAD")
        continue
    try:
        with open(f"{REPO}/{f}") as fh:
            work_src = fh.read()
    except FileNotFoundError:
        failures.append(f"{f}: missing in working tree")
        continue
    try:
        h = normalized(head_src.stdout)
        w = normalized(work_src)
    except SyntaxError as e:
        failures.append(f"{f}: syntax error {e}")
        continue
    if h != w:
        failures.append(f"{f}: AST DIFFERS after docstring strip")

print("TOTAL", len(files))
if failures:
    print("FAIL")
    for x in failures:
        print("  ", x)
else:
    print("ALL_PASS")
